import os
from urllib.parse import urlparse

class AuthorizationServer:
    def __init__(self):
        self.redirect_uris = []
        self.registered_uri = None

    def register(self, redirect_uris):
        self.redirect_uris = [urlparse(r) for r in redirect_uris]
